-- 0000_baseline.sql
--
-- Baseline migration: creates all internal DB tables.
-- Idempotent — uses IF NOT EXISTS so it is safe on existing deployments.
-- Matches the state of migrateInternalDB() as of v0.9.5.
--
-- Future migrations are generated by `drizzle-kit generate` from schema.ts.

-- ── Core tables ─────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS audit_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  timestamp TIMESTAMPTZ NOT NULL DEFAULT now(),
  user_id TEXT,
  user_label TEXT,
  auth_mode TEXT NOT NULL,
  sql TEXT NOT NULL,
  duration_ms INTEGER NOT NULL,
  row_count INTEGER,
  success BOOLEAN NOT NULL,
  error TEXT,
  source_id TEXT,
  source_type TEXT,
  target_host TEXT,
  tables_accessed JSONB,
  columns_accessed JSONB,
  org_id TEXT,
  deleted_at TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_audit_log_timestamp ON audit_log(timestamp);
CREATE INDEX IF NOT EXISTS idx_audit_log_user_id ON audit_log(user_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_source_id ON audit_log(source_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_tables_accessed ON audit_log USING GIN (tables_accessed);
CREATE INDEX IF NOT EXISTS idx_audit_log_columns_accessed ON audit_log USING GIN (columns_accessed);
CREATE INDEX IF NOT EXISTS idx_audit_log_org ON audit_log(org_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_deleted_at ON audit_log(deleted_at) WHERE deleted_at IS NOT NULL;

CREATE TABLE IF NOT EXISTS conversations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id TEXT,
  title TEXT,
  surface TEXT DEFAULT 'web',
  connection_id TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  starred BOOLEAN NOT NULL DEFAULT false,
  share_token VARCHAR(64),
  share_expires_at TIMESTAMPTZ,
  share_mode VARCHAR(10) NOT NULL DEFAULT 'public',
  notebook_state JSONB,
  org_id TEXT,
  deleted_at TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_conversations_user ON conversations(user_id);
CREATE INDEX IF NOT EXISTS idx_conversations_starred ON conversations(user_id, starred) WHERE starred = true;
CREATE UNIQUE INDEX IF NOT EXISTS idx_conversations_share_token ON conversations(share_token) WHERE share_token IS NOT NULL;
DO $$ BEGIN ALTER TABLE conversations ADD CONSTRAINT chk_share_mode CHECK (share_mode IN ('public', 'org')); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE INDEX IF NOT EXISTS idx_conversations_org ON conversations(org_id);

CREATE TABLE IF NOT EXISTS messages (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  conversation_id UUID REFERENCES conversations(id) ON DELETE CASCADE,
  role TEXT NOT NULL,
  content JSONB NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_messages_conversation ON messages(conversation_id);

-- ── Slack integration ───────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS slack_installations (
  team_id TEXT PRIMARY KEY,
  bot_token TEXT NOT NULL,
  org_id TEXT,
  workspace_name TEXT,
  installed_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_slack_installations_org ON slack_installations(org_id);

CREATE TABLE IF NOT EXISTS slack_threads (
  thread_ts TEXT NOT NULL,
  channel_id TEXT NOT NULL,
  conversation_id UUID NOT NULL,
  PRIMARY KEY (thread_ts, channel_id)
);

CREATE INDEX IF NOT EXISTS idx_slack_threads_conversation ON slack_threads(conversation_id);

-- ── Action framework ────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS action_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  requested_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  resolved_at TIMESTAMPTZ,
  executed_at TIMESTAMPTZ,
  requested_by TEXT,
  approved_by TEXT,
  auth_mode TEXT NOT NULL,
  action_type TEXT NOT NULL,
  target TEXT NOT NULL,
  summary TEXT NOT NULL,
  payload JSONB NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  result JSONB,
  error TEXT,
  rollback_info JSONB,
  conversation_id UUID,
  request_id TEXT,
  org_id TEXT
);

CREATE INDEX IF NOT EXISTS idx_action_log_requested_by ON action_log(requested_by);
CREATE INDEX IF NOT EXISTS idx_action_log_status ON action_log(status);
CREATE INDEX IF NOT EXISTS idx_action_log_action_type ON action_log(action_type);
CREATE INDEX IF NOT EXISTS idx_action_log_conversation ON action_log(conversation_id);
CREATE INDEX IF NOT EXISTS idx_action_log_org ON action_log(org_id);

-- ── Scheduled tasks ─────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS scheduled_tasks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  owner_id TEXT NOT NULL,
  name TEXT NOT NULL,
  question TEXT NOT NULL,
  cron_expression TEXT NOT NULL,
