-- ── EE: PII column classifications ─────────────────────────────────────

CREATE TABLE IF NOT EXISTS pii_column_classifications (
  id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
  org_id TEXT NOT NULL,
  table_name TEXT NOT NULL,
  column_name TEXT NOT NULL,
  connection_id TEXT NOT NULL DEFAULT 'default',
  category TEXT NOT NULL,
  confidence TEXT NOT NULL DEFAULT 'medium',
  masking_strategy TEXT NOT NULL DEFAULT 'partial',
  reviewed BOOLEAN NOT NULL DEFAULT false,
  dismissed BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(org_id, table_name, column_name, connection_id)
);

-- ── EE: SCIM group mappings ────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS scim_group_mappings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  org_id TEXT NOT NULL,
  scim_group_name TEXT NOT NULL,
  role_name TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(org_id, scim_group_name)
);

-- ── EE: SLA metrics ────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS sla_metrics (
  id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
  workspace_id TEXT NOT NULL,
  latency_ms DOUBLE PRECISION NOT NULL,
  is_error BOOLEAN NOT NULL DEFAULT false,
  recorded_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_sla_metrics_ws_time ON sla_metrics(workspace_id, recorded_at DESC);

CREATE TABLE IF NOT EXISTS sla_alerts (
  id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
  workspace_id TEXT NOT NULL,
  alert_type TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'firing',
  current_value DOUBLE PRECISION NOT NULL,
  threshold DOUBLE PRECISION NOT NULL,
  message TEXT NOT NULL,
  fired_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  resolved_at TIMESTAMPTZ,
  acknowledged_at TIMESTAMPTZ,
  acknowledged_by TEXT
);

CREATE INDEX IF NOT EXISTS idx_sla_alerts_ws ON sla_alerts(workspace_id, status);

CREATE TABLE IF NOT EXISTS sla_thresholds (
  workspace_id TEXT PRIMARY KEY,
  latency_p99_ms DOUBLE PRECISION NOT NULL DEFAULT 5000,
  error_rate_pct DOUBLE PRECISION NOT NULL DEFAULT 5,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
